class UserProfile {
  final String id;
  final String name;
  final String email;
  final String? avatarUrl;
  final String? phoneNumber;
  final DateTime? lastUpdated;

  UserProfile({
    required this.id,
    required this.name,
    required this.email,
    this.avatarUrl,
    this.phoneNumber,
    this.lastUpdated,
  });

  Map<String, dynamic> toJson() => {
        'id': id,
        'name': name,
        'email': email,
        'avatarUrl': avatarUrl,
        'phoneNumber': phoneNumber,
        'lastUpdated': lastUpdated?.toIso8601String(),
      };

  factory UserProfile.fromJson(Map<String, dynamic> json) => UserProfile(
        id: json['id'] ?? '',
        name: json['name'] ?? '',
        email: json['email'] ?? '',
        avatarUrl: json['avatarUrl'],
        phoneNumber: json['phoneNumber'],
        lastUpdated: json['lastUpdated'] != null
            ? DateTime.parse(json['lastUpdated'])
            : null,
      );

  @override
  String toString() =>
      'UserProfile(id: $id, name: $name, email: $email, avatarUrl: $avatarUrl, phoneNumber: $phoneNumber)';
}

class AuthTokens {
  final String accessToken;
  final String refreshToken;
  final DateTime expiresAt;

  AuthTokens({
    required this.accessToken,
    required this.refreshToken,
    required this.expiresAt,
  });

  bool get isExpired => DateTime.now().isAfter(expiresAt);

  bool get isAboutToExpire =>
      DateTime.now().isAfter(expiresAt.subtract(const Duration(minutes: 5)));

  Map<String, dynamic> toJson() => {
        'accessToken': accessToken,
        'refreshToken': refreshToken,
        'expiresAt': expiresAt.toIso8601String(),
      };

  factory AuthTokens.fromJson(Map<String, dynamic> json) => AuthTokens(
        accessToken: json['accessToken'] ?? '',
        refreshToken: json['refreshToken'] ?? '',
        expiresAt: DateTime.parse(json['expiresAt']),
      );

  @override
  String toString() =>
      'AuthTokens(accessToken: ${accessToken.substring(0, 10)}..., isExpired: $isExpired)';
}

class AppConfig {
  final String apiBaseUrl;
  final String appVersion;
  final bool maintenanceMode;
  final int cacheExpiryMinutes;
  final Map<String, bool> featureFlags;

  AppConfig({
    required this.apiBaseUrl,
    required this.appVersion,
    this.maintenanceMode = false,
    this.cacheExpiryMinutes = 60,
    this.featureFlags = const {},
  });

  Map<String, dynamic> toJson() => {
        'apiBaseUrl': apiBaseUrl,
        'appVersion': appVersion,
        'maintenanceMode': maintenanceMode,
        'cacheExpiryMinutes': cacheExpiryMinutes,
        'featureFlags': featureFlags,
      };

  factory AppConfig.fromJson(Map<String, dynamic> json) => AppConfig(
