        appVersion: json['appVersion'] ?? '1.0.0',
        maintenanceMode: json['maintenanceMode'] ?? false,
        cacheExpiryMinutes: json['cacheExpiryMinutes'] ?? 60,
        featureFlags: Map<String, bool>.from(json['featureFlags'] ?? {}),
      );

  @override
  String toString() =>
      'AppConfig(apiBaseUrl: $apiBaseUrl, appVersion: $appVersion, maintenanceMode: $maintenanceMode)';
}

class CachedItem<T> {
  final T data;
  final DateTime cachedAt;
  final Duration expiryDuration;

  CachedItem({
    required this.data,
    required this.cachedAt,
    this.expiryDuration = const Duration(hours: 1),
  });

  bool get isExpired => DateTime.now().isAfter(cachedAt.add(expiryDuration));
}

// Storage Keys
class StorageKeys {
  static const String accessToken = 'auth_access_token';
  static const String refreshToken = 'auth_refresh_token';
  static const String tokenExpiry = 'auth_token_expiry';
  static const String userProfile = 'user_profile';
  static const String appConfig = 'app_config';
  static const String themeMode = 'pref_theme_mode';
  static const String locale = 'pref_locale';
  static const String notificationsEnabled = 'pref_notifications_enabled';
  static const String biometricEnabled = 'pref_biometric_enabled';
  static const String onboardingComplete = 'pref_onboarding_complete';
  static const String fontSize = 'pref_font_size';
  static const String cachePrefix = 'cache_';
  static const String cacheTimestampPrefix = 'cache_ts_';
  static const String lastSyncTimestamp = 'last_sync_timestamp';
  static const String offlineDataPrefix = 'offline_';
  static const String pendingActionsKey = 'pending_offline_actions';
}

// Local Storage Manager
class LocalStorageManager {
  static LocalStorageManager? _instance;
  SharedPreferences? _prefs;

  LocalStorageManager._();

  static LocalStorageManager get instance {
    _instance ??= LocalStorageManager._();
    return _instance!;
  }

  Future<void> init() async {
    _prefs = await SharedPreferences.getInstance();
  }

  SharedPreferences get _preferences {
    if (_prefs == null) {
      throw Exception(
          'LocalStorageManager not initialized. Call init() first.');
    }
    return _prefs!;
  }

  // ==================== Authentication Tokens ====================

  Future<void> saveAuthTokens(AuthTokens tokens) async {
    await _preferences.setString(StorageKeys.accessToken, tokens.accessToken);
    await _preferences.setString(StorageKeys.refreshToken, tokens.refreshToken);
    await _preferences.setString(
        StorageKeys.tokenExpiry, tokens.expiresAt.toIso8601String());
  }

  AuthTokens? getAuthTokens() {
    final accessToken = _preferences.getString(StorageKeys.accessToken);
    final refreshToken = _preferences.getString(StorageKeys.refreshToken);
    final expiryStr = _preferences.getString(StorageKeys.tokenExpiry);

    if (accessToken == null || refreshToken == null || expiryStr == null) {
      return null;
    }

    return AuthTokens(
      accessToken: accessToken,
      refreshToken: refreshToken,
      expiresAt: DateTime.parse(expiryStr),
    );
  }

  String? getAccessToken() => _preferences.getString(StorageKeys.accessToken);

  String? getRefreshToken() => _preferences.getString(StorageKeys.refreshToken);

  bool get isLoggedIn {
    final tokens = getAuthTokens();
    return tokens != null && !tokens.isExpired;
  }

  bool get hasValidTokens {
    final tokens = getAuthTokens();
    return tokens != null && !tokens.isExpired;
  }

  Future<void> clearAuthTokens() async {
    await _preferences.remove(StorageKeys.accessToken);
    await _preferences.remove(StorageKeys.refreshToken);
    await _preferences.remove(StorageKeys.tokenExpiry);
  }

  // ==================== User Profile ====================

  Future<void> saveUserProfile(UserProfile profile) async {
    final jsonStr = jsonEncode(profile.toJson());
    await _preferences.setString(StorageKeys.userProfile, jsonStr);
  }

  UserProfile? getUserProfile() {
    final jsonStr = _preferences.getString(StorageKeys.userProfile);
    if (jsonStr == null) return null;

    try {
      final json = jsonDecode(jsonStr) as Map<String, dynamic>;
      return UserProfile.fromJson(json);
    } catch (e) {
      debugPrint('Error parsing user profile: $e');
      return null;
    }
  }

  Future<void> clearUserProfile() async {
    await _preferences.remove(StorageKeys.userProfile);
  }

  // ==================== App Configuration ====================

  Future<void> saveAppConfig(AppConfig config) async {
    final jsonStr = jsonEncode(config.toJson());
    await _preferences.setString(StorageKeys.appConfig, jsonStr);
  }

  AppConfig? getAppConfig() {
    final jsonStr = _preferences.getString(StorageKeys.appConfig);
    if (jsonStr == null) return null;

    try {
      final json = jsonDecode(jsonStr) as Map<String, dynamic>;
      return AppConfig.fromJson(json);
    } catch (e) {
      debugPrint('Error parsing app config: $e');
      return null;
    }
  }

  AppConfig getAppConfigOrDefault() {
    return getAppConfig() ??
        AppConfig(
          apiBaseUrl: 'https://api.example.com',
          appVersion: '1.0.0',
        );
  }

  bool isFeatureEnabled(String featureKey) {
    final config = getAppConfig();
    return config?.featureFlags[featureKey] ?? false;
  }

  // ==================== User Preferences ====================

  Future<void> setThemeMode(ThemeMode mode) async {
    await _preferences.setString(StorageKeys.themeMode, mode.name);
  }

  ThemeMode getThemeMode() {
    final modeStr = _preferences.getString(StorageKeys.themeMode);
    switch (modeStr) {
      case 'light':
        return ThemeMode.light;
      case 'dark':
        return ThemeMode.dark;
      default:
        return ThemeMode.system;
    }
  }

  Future<void> setLocale(String languageCode) async {
    await _preferences.setString(StorageKeys.locale, languageCode);
  }

  String getLocale() {
    return _preferences.getString(StorageKeys.locale) ?? 'en';
  }

  Future<void> setNotificationsEnabled(bool enabled) async {
    await _preferences.setBool(StorageKeys.notificationsEnabled, enabled);
  }

  bool get notificationsEnabled {
    return _preferences.getBool(StorageKeys.notificationsEnabled) ?? true;
  }

  Future<void> setBiometricEnabled(bool enabled) async {
    await _preferences.setBool(StorageKeys.biometricEnabled, enabled);
  }

  bool get biometricEnabled {
    return _preferences.getBool(StorageKeys.biometricEnabled) ?? false;
  }

  Future<void> setOnboardingComplete(bool complete) async {
    await _preferences.setBool(StorageKeys.onboardingComplete, complete);
  }

  bool get onboardingComplete {
    return _preferences.getBool(StorageKeys.onboardingComplete) ?? false;
  }

  Future<void> setFontSize(double size) async {
    await _preferences.setDouble(StorageKeys.fontSize, size);
  }

  double get fontSize {
    return _preferences.getDouble(StorageKeys.fontSize) ?? 14.0;
  }

  // ==================== Cache Management ====================

  Future<void> cacheData(String key, dynamic data,
      {Duration expiryDuration = const Duration(hours: 1)}) async {
    final cacheKey = '${StorageKeys.cachePrefix}$key';
    final timestampKey = '${StorageKeys.cacheTimestampPrefix}$key';

    final jsonStr = jsonEncode(data);
    await _preferences.setString(cacheKey, jsonStr);
    await _preferences.setString(
      timestampKey,
      DateTime.now().add(expiryDuration).toIso8601String(),
    );
  }

  T? getCachedData<T>(String key, T Function(dynamic json) fromJson) {
    final cacheKey = '${StorageKeys.cachePrefix}$key';
    final timestampKey = '${StorageKeys.cacheTimestampPrefix}$key';

    final expiryStr = _preferences.getString(timestampKey);
    if (expiryStr != null) {
      final expiry = DateTime.parse(expiryStr);
      if (DateTime.now().isAfter(expiry)) {
        // Cache expired, remove it
        _preferences.remove(cacheKey);
        _preferences.remove(timestampKey);
        return null;
      }
    }

    final jsonStr = _preferences.getString(cacheKey);
    if (jsonStr == null) return null;

    try {
      final json = jsonDecode(jsonStr);
      return fromJson(json);
    } catch (e) {
      debugPrint('Error parsing cached data for key $key: $e');
      return null;
    }
  }

  dynamic getRawCachedData(String key) {
    final cacheKey = '${StorageKeys.cachePrefix}$key';
    final timestampKey = '${StorageKeys.cacheTimestampPrefix}$key';

    final expiryStr = _preferences.getString(timestampKey);
    if (expiryStr != null) {
      final expiry = DateTime.parse(expiryStr);
      if (DateTime.now().isAfter(expiry)) {
        _preferences.remove(cacheKey);
        _preferences.remove(timestampKey);
        return null;
      }
    }

    final jsonStr = _preferences.getString(cacheKey);
    if (jsonStr == null) return null;

    try {
      return jsonDecode(jsonStr);
    } catch (e) {
      return null;
    }
  }

  bool isCacheValid(String key) {
    final timestampKey = '${StorageKeys.cacheTimestampPrefix}$key';
    final expiryStr = _preferences.getString(timestampKey);
    if (expiryStr == null) return false;

    final expiry = DateTime.parse(expiryStr);
    return DateTime.now().isBefore(expiry);
  }

  Future<void> invalidateCache(String key) async {
    final cacheKey = '${StorageKeys.cachePrefix}$key';
    final timestampKey = '${StorageKeys.cacheTimestampPrefix}$key';
    await _preferences.remove(cacheKey);
    await _preferences.remove(timestampKey);
  }

  Future<void> clearAllCache() async {
    final keys = _preferences.getKeys();
    for (final key in keys) {
      if (key.startsWith(StorageKeys.cachePrefix) ||
          key.startsWith(StorageKeys.cacheTimestampPrefix)) {
        await _preferences.remove(key);
      }
    }
  }

  // ==================== Offline Data Management ====================

  Future<void> saveOfflineData(String key, dynamic data) async {
    final offlineKey = '${StorageKeys.offlineDataPrefix}$key';
    final jsonStr = jsonEncode(data);
    await _preferences.setString(offlineKey, jsonStr);
  }

  dynamic getOfflineData(String key) {
    final offlineKey = '${StorageKeys.offlineDataPrefix}$key';
    final jsonStr = _preferences.getString(offlineKey);
    if (jsonStr == null) return null;

    try {
      return jsonDecode(jsonStr);
    } catch (e) {
      debugPrint('Error parsing offline data for key $key: $e');
      return null;
    }
  }

  Future<void> removeOfflineData(String key) async {
    final offlineKey = '${StorageKeys.offlineDataPrefix}$key';
    await _preferences.remove(offlineKey);
  }

  Future<void> clearAllOfflineData() async {
    final keys = _preferences.getKeys();
    for (final key in keys) {
      if (key.startsWith(StorageKeys.offlineDataPrefix)) {
        await _preferences.remove(key);
      }
    }
  }

  // ==================== Pending Offline Actions ====================

  Future<void> addPendingAction(Map<String, dynamic> action) async {
    final actions = getPendingActions();
    action['timestamp'] = DateTime.now().toIso8601String();
    action['id'] = DateTime.now().millisecondsSinceEpoch.toString();
    actions.add(action);
    await _preferences.setString(
        StorageKeys.pendingActionsKey, jsonEncode(actions));
  }

  List<Map<String, dynamic>> getPendingActions() {
    final jsonStr = _preferences.getString(StorageKeys.pendingActionsKey);
    if (jsonStr == null) return [];

    try {
      final list = jsonDecode(jsonStr) as List;
      return list.cast<Map<String, dynamic>>();
    } catch (e) {
      debugPrint('Error parsing pending actions: $e');
      return [];
    }
  }

  Future<void> removePendingAction(String actionId) async {
    final actions = getPendingActions();
    actions.removeWhere((action) => action['id'] == actionId);
    await _preferences.setString(
        StorageKeys.pendingActionsKey, jsonEncode(actions));
  }

  Future<void> clearPendingActions() async {
    await _preferences.remove(StorageKeys.pendingActionsKey);
  }

  // ==================== Sync Management ====================

  Future<void> updateLastSyncTimestamp() async {
    await _preferences.setString(
        StorageKeys.lastSyncTimestamp, DateTime.now().toIso8601String());
  }

  DateTime? getLastSyncTimestamp() {
    final str = _preferences.getString(StorageKeys.lastSyncTimestamp);
    if (str == null) return null;
    return DateTime.parse(str);
  }

  bool needsSync({Duration threshold = const Duration(minutes: 30)}) {
    final lastSync = getLastSyncTimestamp();
    if (lastSync == null) return true;
    return DateTime.now().difference(lastSync) > threshold;
  }

  // ==================== Generic Helpers ====================

  Future<void> setString(String key, String value) async {
    await _preferences.setString(key, value);
  }

  String? getString(String key) => _preferences.getString(key);

  Future<void> setInt(String key, int value) async {
    await _preferences.setInt(key, value);
  }

  int? getInt(String key) => _preferences.getInt(key);

  Future<void> setBool(String key, bool value) async {
    await _preferences.setBool(key, value);
  }

  bool? getBool(String key) => _preferences.getBool(key);

  Future<void> setDouble(String key, double value) async {
    await _preferences.setDouble(key, value);
  }

  double? getDouble(String key) => _preferences.getDouble(key);

  Future<void> setStringList(String key, List<String> value) async {
    await _preferences.setStringList(key, value);
  }

  List<String>? getStringList(String key) => _preferences.getStringList(key);

  Future<void> remove(String key) async {
    await _preferences.remove(key);
  }

  bool containsKey(String key) => _preferences.containsKey(key);

  Set<String> getAllKeys() => _preferences.getKeys();

  // ==================== Logout / Clear All ====================

  Future<void> logout() async {
    await clearAuthTokens();
    await clearUserProfile();
    await clearAllCache();
    await clearPendingActions();
    // Preserve user preferences (theme, locale, etc.)
  }

  Future<void> clearAll() async {
    await _preferences.clear();
  }

  // ==================== Storage Info ====================

  Map<String, dynamic> getStorageInfo() {
    final keys = _preferences.getKeys();
    int cacheCount = 0;
    int offlineCount = 0;
    int prefCount = 0;

    for (final key in keys) {
      if (key.startsWith(StorageKeys.cachePrefix)) {
        cacheCount++;
      } else if (key.startsWith(StorageKeys.offlineDataPrefix)) {
        offlineCount++;
      } else if (key.startsWith('pref_')) {
        prefCount++;
      }
    }

    return {
      'totalKeys': keys.length,
      'cacheEntries': cacheCount,
      'offlineEntries': offlineCount,
      'preferenceEntries': prefCount,
      'isLoggedIn': isLoggedIn,
      'lastSync': getLastSyncTimestamp()?.toIso8601String(),
      'pendingActions': getPendingActions().length,
    };
  }
}

