                  _buttonRow([
                    _actionButton(
                        'Save Profile', Icons.person_add, _saveUserProfile),
                    _actionButton(
                        'Read Profile', Icons.person, _readUserProfile),
                  ]),
                  const SizedBox(height: 8),
                  _sectionTitle('App Config'),
                  _buttonRow([
                    _actionButton(
                        'Save Config', Icons.settings, _saveAppConfig),
                    _actionButton('Read Config', Icons.tune, _readAppConfig),
                  ]),
                  const SizedBox(height: 8),
                  _sectionTitle('Cache & Offline'),
                  _buttonRow([
                    _actionButton(
                        'Test Cache', Icons.cached, _testCaching),
                    _actionButton('Test Offline', Icons.cloud_off,
                        _testOfflineData),
                  ]),
                  const SizedBox(height: 8),
                  _sectionTitle('Preferences & Sync'),
                  _buttonRow([
                    _actionButton(
                        'Test Prefs', Icons.tune, _testPreferences),
                    _actionButton(
                        'Test Sync', Icons.sync, _testSyncManagement),
                  ]),
                  const SizedBox(height: 8),
                  _sectionTitle('Management'),
                  _buttonRow([
                    _actionButton('Storage Info', Icons.info, _showStorageInfo),
                    _actionButton(
                        'Clear Cache', Icons.delete_outline, _clearCache),
                  ]),
                  _buttonRow([
                    _actionButton('Logout', Icons.logout, _logout),
                    _actionButton(
                        'Clear All', Icons.delete_forever, _clearAll),
                  ]),
                ],
              ),
            ),
          ),
          const Divider(height: 1),
          Expanded(
            flex: 3,
            child: Container(
              color: Colors.grey.shade900,
              width: double.infinity,
              padding: const EdgeInsets.all(12),
              child: SingleChildScrollView(
                reverse: false,
                child: Text(
                  _output,
                  style: const TextStyle(
                    fontFamily: 'monospace',
                    fontSize: 12,
                    color: Colors.greenAccent,
                  ),
                ),
              ),
            ),
          ),
        ],
      ),
    );
  }

  Widget _sectionTitle(String title) {
    return Padding(
      padding: const EdgeInsets.only(bottom: 4, top: 4),
      child: Text(
        title,
        style: TextStyle(
          fontSize: 13,
          fontWeight: FontWeight.bold,
          color: Theme.of(context).colorScheme.primary,
        ),
      ),
    );
  }

  Widget _buttonRow(List<Widget> buttons) {
    return Row(
      children: buttons
          .map((b) => Expanded(
                child: Padding(
                  padding: const EdgeInsets.symmetric(horizontal: 2),
                  child: b,
                ),
              ))
          .toList(),
    );
  }

  Widget _actionButton(
      String label, IconData icon, VoidCallback onPressed) {
    return Padding(
      padding: const EdgeInsets.only(bottom: 4),
      child: ElevatedButton.icon(
        onPressed: onPressed,
        icon: Icon(icon, size: 16),
        label: Text(label, style: const TextStyle(fontSize: 11)),
        style: ElevatedButton.styleFrom(
          padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 8),
          minimumSize: const Size(0, 36),
        ),
      ),
    );
  }
}